B.J5=new A.c8("economic_law","\uc57d\uad00\ubc95","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc57d\uad00\uc758 \uba85\uc2dc\xb7\uc124\uba85\uc758\ubb34\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.CK,4,"\uacc4\uc57d\uc758 \uc131\uc9c8\uc0c1 \uc124\uba85\uc774 \ud604\uc800\ud788 \uace4\ub780\ud55c \uacbd\uc6b0 \uc124\uba85\uc758\ubb34\ub294 \uc608\uc678\uc801\uc73c\ub85c \uba74\uc81c\ub41c\ub2e4. \uc5ec\uac1d\uc6b4\uc1a1\uc5c5 \ub4f1 \uc77c\ubd80 \uc5c5\uc885\uc740 \uba85\uc2dc\xb7\uad50\ubd80\uc758\ubb34\ub9cc \uba74\uc81c\ub418\uace0 \uc124\uba85\uc758\ubb34\ub294 \ub0a8\ub294\ub2e4\ub294 \uc810\uacfc \uad6c\ubd84\ud574\uc57c \ud568.",B.E3)
B.Ey=s(["\uc0ac\uc5c5\uc790 \ubc0f \uc0ac\uc5c5\uc790\ub2e8\uccb4\ub294 \ud45c\uc900\uc774 \ub420 \uc57d\uad00\uc744 \ub9c8\ub828\ud558\uc5ec \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \uadf8 \uc2ec\uc0ac\ub97c \uccad\uad6c\ud560 \uc218 \uc788\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc18c\ube44\uc790\ub2e8\uccb4 \ub4f1\uc758 \uc694\uccad\uc774 \uc788\ub294 \uacbd\uc6b0 \ud45c\uc900\uc57d\uad00\uc758 \uc81c\uc815\xb7\uac1c\uc815\uc548\uc744 \ub9c8\ub828\ud558\uc5ec \uc2ec\uc0ac\uccad\uad6c\ud560 \uac83\uc744 \uad8c\uace0\ud560 \uc218 \uc788\ub2e4","\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\ub294 \uc0ac\uc5c5\uc790\ub294 \ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub974\uac8c \uc815\ud55c \uc8fc\uc694 \ub0b4\uc6a9\uc774 \uc788\uc73c\uba74 \ud45c\uc900\uc57d\uad00\ubcf4\ub2e4 \uace0\uac1d\uc5d0\uac8c \ub354 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\ub3c4 \uc790\uc720\ub86d\uac8c \uc0ac\uc6a9\ud560 \uc218 \uc788\ub2e4","\ud45c\uc900\uc57d\uad00\uacfc \ub2e4\ub974\uac8c \uc815\ud55c \uc8fc\uc694 \ub0b4\uc6a9\uc740 \uace0\uac1d\uc774 \uc54c\uae30 \uc27d\uac8c \ud45c\uc2dc\ud558\uc5ec\uc57c \ud55c\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ud45c\uc900\uc57d\uad00\uc758 \uc0ac\uc6a9\uc744 \ud65c\uc131\ud654\ud558\uae30 \uc704\ud558\uc5ec \ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
