B.J7=new A.c8("economic_law","\uc57d\uad00\ubc95","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ud45c\uc900\uc57d\uad00 \uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Ey,2,"\ud45c\uc900\uc57d\uad00 \ud45c\uc9c0\ub97c \uc0ac\uc6a9\ud558\uba74\uc11c \ud45c\uc900\uc57d\uad00\ubcf4\ub2e4 \uace0\uac1d\uc5d0\uac8c \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc744 \uc815\ud558\ub294 \uac83\uc740 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\uc73c\uba70, \uadf8 \ubd88\ub9ac\ud55c \ub0b4\uc6a9\uc740 \ubb34\ud6a8\ub85c \ub2e4\ub904\uc9c4\ub2e4.",B.DF)
B.CI=s(["\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ubc94\uc704\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uc0c1\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\ubaa9\uc801\ubb3c\uc5d0 \uad00\ud558\uc5ec \uacac\ubcf8\uc774 \uc81c\uc2dc\ub41c \uacbd\uc6b0 \uadf8 \ubcf4\uc7a5\ub41c \ub0b4\uc6a9\uc5d0 \ub300\ud55c \ucc45\uc784\uc744 \ubc30\uc81c\ud558\ub294 \uc870\ud56d","\ubc95\ub960\uc5d0 \ub530\ub978 \uace0\uac1d\uc758 \ud574\uc81c\uad8c\xb7\ud574\uc9c0\uad8c\uc744 \ubc30\uc81c\ud558\uac70\ub098 \uadf8 \ud589\uc0ac\ub97c \uc81c\ud55c\ud558\ub294 \uc870\ud56d","\uace0\uac1d\uc5d0\uac8c \ubd80\ub2f9\ud558\uac8c \uacfc\uc911\ud55c \uc9c0\uc5f0\uc190\ud574\uae08 \ub4f1\uc758 \uc190\ud574\ubc30\uc0c1\uc758\ubb34\ub97c \ubd80\ub2f4\uc2dc\ud0a4\ub294 \uc870\ud56d","\uacc4\uc57d\ud574\uc9c0 \uc2dc \uacc4\uc57d\ub2f9\uc2dc\uc758 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \uc0ac\uc5c5\uc790\uc640 \uace0\uac1d \uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704 \ub0b4\uc5d0\uc11c \ubd80\uc5ec\ud558\ub294 \uc870\ud56d"],t.s)
B.F1=s(["\ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d \ubb34\ud6a8\uc0ac\uc720"],t.s)
B.IX=new A.c8("economic_law","\uc57d\uad00\ubc95","\uc57d\uad00\uc758 \uaddc\uc81c\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubb34\ud6a8\uc778 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.CI,4,"\uc30d\ubc29\uc5d0\uac8c \uc815\ub2f9\ud55c \ubc94\uc704\uc758 \uc6d0\uc0c1\ud68c\ubcf5\uc758\ubb34\ub97c \ubd80\uc5ec\ud558\ub294 \uac83\uc740 \ubd88\uacf5\uc815\uc57d\uad00\uc870\ud56d\uc774 \uc544\ub2c8\ub2e4. \ubd80\ub2f9\ud558\uac8c \uc0ac\uc5c5\uc790\uc5d0\uac8c\ub9cc \uc720\ub9ac\ud558\uac70\ub098 \uace0\uac1d\uc5d0\uac8c \uacfc\uc911\ud55c \ubd80\ub2f4\uc744 \uc9c0\uc6b0\ub294 \uc870\ud56d\uc774 \ubb34\ud6a8 \uc0ac\uc720\uc5d0 \ud574\ub2f9\ud55c\ub2e4.",B.F1)
B.D7=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc870\uc0ac\ub97c \ubc1b\uace0 \uc788\ub294 \uc0ac\uc5c5\uc790\ub294 \uc870\uc0ac \ub300\uc0c1 \ud589\uc704\ub85c \uc778\ud55c \uacbd\uc7c1\uc81c\ud55c\uc0c1\ud0dc\uc758 \uc790\ubc1c\uc801 \ud574\uc18c\ub97c \uc704\ud558\uc5ec \ub3d9\uc758\uc758\uacb0\uc744 \uc2e0\uccad\ud560 \uc218 \uc788\ub2e4","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uc5d0 \ub300\ud574\uc11c\ub294 \uc6d0\uce59\uc801\uc73c\ub85c \ub3d9\uc758\uc758\uacb0\uc744 \ud560 \uc218 \uc5c6\ub2e4","\ub3d9\uc758\uc758\uacb0\uc740 \ud574\ub2f9 \ud589\uc704\uac00 \uc774 \ubc95\uc5d0 \uc704\ubc18\ub41c\ub2e4\uace0 \uc778\uc815\ud55c \uac83\uc744 \uc758\ubbf8\ud55c\ub2e4","\uc2e0\uccad\uc778\uc774 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub3d9\uc758\uc758\uacb0\uc744 \uc774\ud589\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \uacbd\uc6b0 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ub3d9\uc758\uc758\uacb0\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4","\ub3d9\uc758\uc758\uacb0\uc774 \uc788\uae30 \uc804\uc774\ub77c\ub3c4 \uc2e0\uccad\uc778\uc740 \uc2e0\uccad\uc744 \ucde8\uc18c\ud560 \uc218 \uc788\ub2e4"],t.s)
B.DE=s(["\ub3d9\uc758\uc758\uacb0\uc81c\ub3c4"],t.s)
B.J_=new A.c8("economic_law","\uacf5\uc815\uc704 \uc870\uc9c1\xb7\uc808\ucc28","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ub3d9\uc758\uc758\uacb0\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.D7,2,"\ub3d9\uc758\uc758\uacb0\uc740 \uc704\ubc95\uc131\uc744 \uc778\uc815\ud55c \uac83\uc774 \uc544\ub2c8\ub77c \uc2e0\uccad\uc778\uc774 \uc81c\ucd9c\ud55c \uc2dc\uc815\ubc29\uc548\uacfc \uac19\uc740 \ucde8\uc9c0\ub85c \uc0ac\uac74\uc744 \uc2e0\uc18d\ud788 \uc885\uacb0\ud558\ub294 \uc81c\ub3c4\uc774\ub2e4.",B.DE)
B.E6=s(["\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \ubc95 \uc704\ubc18 \uc0ac\uc5c5\uc790\uac00 \ud569\ubcd1\uc73c\ub85c \uc18c\uba78\ud55c \uacbd\uc6b0 \uc874\uc18d\ud558\ub294 \ud68c\uc0ac\uc5d0 \ub300\ud558\uc5ec \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\xb7\uc9d5\uc218\ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ubc1b\uc740 \ud68c\uc0ac\uac00 \ubd84\ud560\ub418\ub294 \uacbd\uc6b0 \ubd84\ud560\ub418\ub294 \ud68c\uc0ac\uc640 \uc2e0\uc124\ud68c\uc0ac\ub294 \uadf8 \uacfc\uc9d5\uae08\uc744 \uc5f0\ub300\ud558\uc5ec \ub0a9\ubd80\ud560 \ucc45\uc784\uc744 \uc9c4\ub2e4","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uc758\ubb34\uc790\uac00 \ubb34\uc790\ub825\uc774 \ub418\uc5b4 \uc9d5\uc218\uac00 \ubd88\uac00\ub2a5\ud574\uc9c4 \uacbd\uc6b0 \uacb0\uc190\ucc98\ubd84\uc744 \ud560 \uc218 \uc788\ub2e4","\uacfc\uc9d5\uae08 \ub0a9\ubd80\uae30\ud55c\uc758 \uc5f0\uae30\ub97c \uc2e0\uccad\ud558\ub824\ub294 \uc790\ub294 \ub0a9\ubd80\ud1b5\uc9c0\ub97c \ubc1b\uc740 \ub0a0\ubd80\ud130 60\uc77c \uc774\ub0b4\uc5d0 \uc2e0\uccad\ud558\uc5ec\uc57c \ud55c\ub2e4","\uacfc\uc9d5\uae08\uc740 \ud615\ubc8c\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c \ub3d9\uc77c\ud55c \ud589\uc704\uc5d0 \ub300\ud558\uc5ec \ubc8c\uae08\uacfc \uacfc\uc9d5\uae08\uc744 \ud568\uaed8 \ubd80\uacfc\ud560 \uc218 \uc5c6\ub2e4"],t.s)
B.Ew=s(["\uacfc\uc9d5\uae08\uc758 \ubc95\uc801 \uc131\uc9c8"],t.s)
B.J1=new A.c8("economic_law","\uacf5\uc815\uc704 \uc870\uc9c1\xb7\uc808\ucc28","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacfc\uc9d5\uae08\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.E6,4,"\uacfc\uc9d5\uae08\uc740 \ud589\uc815\uc81c\uc7ac\uc801 \uc131\uaca9\uc758 \uae08\uc804\uc801 \uc81c\uc7ac\ub85c\uc11c \ud615\ubc8c\uc774 \uc544\ub2c8\uba70, \ubc8c\uae08\uacfc \ubcd1\uacfc\ub418\uc5b4\ub3c4 \uc774\uc911\ucc98\ubc8c\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4\ub294 \uac83\uc774 \ud310\ub840\uc758 \uc785\uc7a5\uc774\ub2e4.",B.Ew)
B.Ef=s(["\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uae08\uc9c0 \uaddc\uc815\uc744 \uc704\ubc18\ud558\uc5ec \uc190\ud574\ub97c \uc785\uc740 \uc790\uac00 \uc788\ub294 \uacbd\uc6b0, \uc0ac\uc5c5\uc790\ub294 \uc790\uc2e0\uc5d0\uac8c \uace0\uc758 \ub610\ub294 \uacfc\uc2e4\uc774 \uc5c6\uc5c8\uc74c\uc744 \ub4e4\uc5b4 \ucc45\uc784\uc744 \uba74\ud560 \uc218 \uc5c6\ub2e4","\uc790\uc9c4\uc2e0\uace0 \ub4f1\uc73c\ub85c \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc744 \uac10\uba74\ubc1b\uc740 \uc0ac\uc5c5\uc790\uc758 \uc190\ud574\ubc30\uc0c1\ucc45\uc784\uc740 \ubc1c\uc0dd\ud55c \uc190\ud574\ub97c \ucd08\uacfc\ud558\uc9c0 \uc54a\ub294 \ubc94\uc704\ub85c \ud55c\uc815\ub420 \uc218 \uc788\ub2e4","\ubc95\uc6d0\uc740 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\uc758 \uc18c\uac00 \uc81c\uae30\ub41c \ub54c \ud544\uc694\ud558\uba74 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc5d0 \ud574\ub2f9 \uc0ac\uac74\uae30\ub85d\uc758 \uc1a1\ubd80\ub97c \uc694\uad6c\ud560 \uc218 \uc788\ub2e4","\uc190\ud574\uac00 \ubc1c\uc0dd\ud55c \uc0ac\uc2e4\uc740 \uc778\uc815\ub418\ub098 \uc190\ud574\uc561\uc744 \uc99d\uba85\ud558\uae30 \uc704\ud574 \ud544\uc694\ud55c \uc0ac\uc2e4\uc744 \uc99d\uba85\ud558\ub294 \uac83\uc774 \uc0ac\uc548\uc758 \uc131\uc9c8\uc0c1 \uace4\ub780\ud55c \uacbd\uc6b0, \ubc95\uc6d0\uc740 \uc190\ud574\ubc30\uc0c1\uccad\uad6c\ub97c \uae30\uac01\ud558\uc5ec\uc57c \ud55c\ub2e4","\ubc95\uc6d0\uc740 \ub2f9\uc0ac\uc790\uac00 \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc790\ub8cc\uc81c\ucd9c\uba85\ub839\uc5d0 \ub530\ub974\uc9c0 \uc544\ub2c8\ud55c \uacbd\uc6b0 \uc790\ub8cc\uc758 \uae30\uc7ac\uc5d0 \uad00\ud55c \uc0c1\ub300\ubc29\uc758 \uc8fc\uc7a5\uc744 \uc9c4\uc2e4\ud55c \uac83\uc73c\ub85c \uc778\uc815\ud560 \uc218 \uc788\ub2e4"],t.s)
B.Ek=s(["\uc190\ud574\ubc30\uc0c1\ucc45\uc784","\uc190\ud574\uc561 \uc778\uc815"],t.s)
B.Jd=new A.c8("economic_law","\uacf5\uc815\uc704 \uc870\uc9c1\xb7\uc808\ucc28","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc190\ud574\ubc30\uc0c1 \ucc45\uc784\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.Ef,3,"\uc190\ud574\uc561 \uc99d\uba85\uc774 \uc0ac\uc548\uc758 \uc131\uc9c8\uc0c1 \uace4\ub780\ud55c \uacbd\uc6b0 \ubc95\uc6d0\uc740 \uccad\uad6c\ub97c \uae30\uac01\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \ubcc0\ub860 \uc804\uccb4\uc758 \ucde8\uc9c0\uc640 \uc99d\uac70\uc870\uc0ac \uacb0\uacfc\uc5d0 \uae30\ucd08\ud558\uc5ec \uc0c1\ub2f9\ud55c \uc190\ud574\uc561\uc744 \uc778\uc815\ud560 \uc218 \uc788\ub2e4.",B.Ek)
B.E0=s(["\u3131, \u3134, \u3137","\u3131, \u3137, \u3139","\u3134, \u3137, \u3139","\u3134, \u3139, \u3141","\u3137, \u3139, \u3141"],t.s)
B.Er=s(["\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \ud558\uc704\uc720\ud615"],t.s)
B.J4=new A.c8("economic_law","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd88\uacf5\uc815\uac70\ub798\ud589\uc704 \uc720\ud615 \uc911 \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uad6c\uc785\uac15\uc81c  \u3134. \ubd80\ub2f9\uc5fc\ub9e4  \u3137. \uc774\uc775\uc81c\uacf5\uac15\uc694  \u3139. \ud310\ub9e4\ubaa9\ud45c\uac15\uc81c  \u3141. \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c",B.E0,1,"\uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9\uc758 \ud558\uc704 \uc720\ud615\uc740 \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\xb7\ubd88\uc774\uc775\uc81c\uacf5\xb7\uacbd\uc601\uac04\uc12d\uc774\ub2e4. \ubd80\ub2f9\uc5fc\ub9e4\uc640 \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c\ub294 \ubcc4\ub3c4\uc758 \uc720\ud615\uc774\ub2e4.",B.Er)
B.DK=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \uac00\uc9c0\uae09\uae08\xb7\ub300\uc5ec\uae08 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \ubd80\ub3d9\uc0b0\xb7\uc720\uac00\uc99d\uad8c\xb7\uc0c1\ud488 \ub4f1\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \ub9e4\ub9e4\ud558\ub294 \ud589\uc704","\ud2b9\uc218\uad00\uacc4\uc778 \ub610\ub294 \ub2e4\ub978 \ud68c\uc0ac\uc5d0 \uc778\ub825\uc744 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc81c\uacf5\ud558\ub294 \ud589\uc704","\uc9c1\uc811 \uac70\ub798\ud558\uba74 \uc0c1\ub2f9\ud788 \uc720\ub9ac\ud568\uc5d0\ub3c4 \uac70\ub798\ub2e8\uacc4\ub97c \ucd94\uac00\ud558\uc5ec \ub2e4\ub978 \ud68c\uc0ac\ub97c \ub9e4\uac1c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704","\uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1 \uc9c0\uae09\ub418\ub294 \ub300\uac00\ubcf4\ub2e4 \ub0ae\uc740 \ub300\uac00\ub85c \uc790\uae30\uc758 \uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uacf5\uae09\ud558\ub294 \ud589\uc704"],t.s)
B.DW=s(["\ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704","\ubd80\ub2f9\uc5fc\ub9e4\uc640 \uad6c\ubd84"],t.s)
B.IY=new A.c8("economic_law","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uc9c0\uc6d0\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.DK,4,"\ub9c8\uc9c0\ub9c9 \uc120\ud0dd\uc9c0\ub294 \ubd80\ub2f9\uc5fc\ub9e4\ub85c, \uacbd\uc7c1\uc0ac\uc5c5\uc790 \ubc30\uc81c \uc720\ud615\uc5d0 \ud574\ub2f9\ud558\uba70 \ubd80\ub2f9\uc9c0\uc6d0\ud589\uc704\uc640\ub294 \uad6c\ubd84\ub41c\ub2e4.",B.DW)
B.Ex=s(["\ubd80\ub2f9\ud558\uac8c \uac70\ub798\uc0c1\ub300\ubc29\uc774 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc758 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \uc54a\ub294 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\ub294 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc758 \uac70\ub798\uc9c0\uc5ed\uc744 \ubd80\ub2f9\ud558\uac8c \uad6c\uc18d\ud558\ub294 \ud589\uc704\ub294 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9\uc5d0 \ud574\ub2f9\ud55c\ub2e4","\uac70\ub798\uc0c1\ub300\ubc29\uc744 \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uc640\ub9cc \uac70\ub798\ud558\ub3c4\ub85d \uad6c\uc18d\ud558\ub294 \uac83\uc740 \ud56d\uc0c1 \uc801\ubc95\ud558\ub2e4","\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\ub294 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc758 \ud558\uc704 \uc720\ud615\uc774\ub2e4","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704\uc5d0\ub9cc \uc801\uc6a9\ub41c\ub2e4"],t.s)
B.F8=s(["\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798","\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798"],t.s)
B.IW=new A.c8("economic_law","\ubd88\uacf5\uc815\uac70\ub798\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740?",B.Ex,0,"\ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798\ub294 \ubd80\ub2f9\ud558\uac8c \uac70\ub798\uc0c1\ub300\ubc29\uc774 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \uc54a\uc744 \uac83\uc744 \uc870\uac74\uc73c\ub85c \uac70\ub798\ud558\ub294 \ud589\uc704\uc774\uba70, \uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798\uc758 \ub300\ud45c\uc801 \ud558\uc704 \uc720\ud615\uc774\ub2e4.",B.F8)
B.F_=s(["\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc0ac\uc2e4\uc744 \uc790\uc9c4\uc2e0\uace0\ud558\uac70\ub098 \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc790\uc5d0 \ub300\ud574\uc11c\ub294 \uc2dc\uc815\uc870\uce58 \ub610\ub294 \uacfc\uc9d5\uae08\uc744 \uac10\uacbd\ud558\uac70\ub098 \uba74\uc81c\ud560 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud55c \uac10\uba74 \ud61c\ud0dd\uc740 \ud615\uc0ac\uace0\ubc1c\uc5d0\ub3c4 \uc801\uc6a9\ub418\uc5b4 \uace0\ubc1c\uc744 \uba74\uc81c\ud560 \uc218 \uc788\ub2e4","\uc790\uc9c4\uc2e0\uace0 \uac10\uba74\uc81c\ub3c4\ub294 \ub3d9\uc77c\ud55c \uc0ac\uc5c5\uc790\uac00 \ubc18\ubcf5\uc801\uc73c\ub85c \uc790\uc9c4\uc2e0\uace0\ud558\ub294 \uacbd\uc6b0\uc5d0\ub3c4 \ud56d\uc0c1 \ub3d9\uc77c\ud558\uac8c \uac10\uba74 \ud61c\ud0dd\uc744 \ubd80\uc5ec\ud558\uc5ec\uc57c \ud55c\ub2e4","\uc99d\uac70\uc81c\uacf5 \ub4f1\uc758 \ubc29\ubc95\uc73c\ub85c \uc870\uc0ac\uc5d0 \ud611\uc870\ud55c \uc790\uc5d0 \ub300\ud558\uc5ec \uc2dc\uc815\uc870\uce58\ub098 \uacfc\uc9d5\uae08\uc758 \uac10\uacbd \ub610\ub294 \uba74\uc81c\uac00 \uac00\ub2a5\ud558\ub2e4","\uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\ub294 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc758 \ub3d9\uc758 \uc5c6\uc774 \uadf8 \uc2e0\uc6d0 \ub4f1 \uad00\ub828 \uc790\ub8cc\ub97c \ub2e4\ub978 \ubaa9\uc801\uc73c\ub85c \uc0ac\uc6a9\ud574\uc11c\ub294 \uc548 \ub41c\ub2e4"],t.s)
B.DB=s(["\uc790\uc9c4\uc2e0\uace0\uc790 \uac10\uba74(\ub9ac\ub2c8\uc5b8\uc2dc)"],t.s)
B.J6=new A.c8("economic_law","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704 \uc790\uc9c4\uc2e0\uace0\uc790 \ub4f1\uc5d0 \ub300\ud55c \uac10\uba74\uc81c\ub3c4\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740?",B.F_,2,"\ubc18\ubcf5\uc801 \uc790\uc9c4\uc2e0\uace0\uc790\uc5d0 \ub300\ud574\uc11c\ub294 \uac10\uba74 \ud61c\ud0dd\uc774 \ubc30\uc81c\ub420 \uc218 \uc788\ub2e4\ub294 \uac83\uc774 \ub9ac\ub2c8\uc5b8\uc2dc \uc81c\ub3c4\uc758 \ucde8\uc9c0\uc774\uba70, \uac10\uba74\uc774 \ud56d\uc0c1 \ubcf4\uc7a5\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4.",B.DB)
B.EN=s(["\ubd88\ud669\uadf9\ubcf5\uc744 \uc704\ud55c \uc0b0\uc5c5\uad6c\uc870\uc870\uc815","\uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c","\uac70\ub798\uc870\uac74\uc758 \ud569\ub9ac\ud654","\uc911\uc18c\uae30\uc5c5\uc758 \uacbd\uc7c1\ub825 \ud5a5\uc0c1","\ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300"],t.s)
B.DZ=s(["\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720"],t.s)
B.IZ=new A.c8("economic_law","\ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\uac00 \uc608\uc678\uc801\uc73c\ub85c \ud5c8\uc6a9\ub420 \uc218 \uc788\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uc758 \uc778\uac00 \ubaa9\uc801\uc73c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.EN,4,"\uacf5\ub3d9\ud589\uc704 \uc778\uac00\uc0ac\uc720\ub294 \uc0b0\uc5c5\ud569\ub9ac\ud654, \uc5f0\uad6c\xb7\uae30\uc220\uac1c\ubc1c, \ubd88\ud669\uadf9\ubcf5 \uad6c\uc870\uc870\uc815, \uc0b0\uc5c5\uad6c\uc870\uc870\uc815, \uac70\ub798\uc870\uac74 \ud569\ub9ac\ud654, \uc911\uc18c\uae30\uc5c5 \uacbd\uc7c1\ub825 \ud5a5\uc0c1 \ub4f1\uc774\uba70, \ub300\uae30\uc5c5\uc758 \uc2dc\uc7a5\uc810\uc720\uc728 \ud655\ub300\ub294 \uc778\uac00\uc0ac\uc720\uac00 \uc544\ub2c8\ub2e4.",B.DZ)
B.E8=s(["\uc2dc\uc7a5\uc810\uc720\uc728 55%\uc778 \ub2e8\uc77c \uc0ac\uc5c5\uc790 A","\uc2dc\uc7a5\uc810\uc720\uc728 40%\uc778 B\uc640 \uc2dc\uc7a5\uc810\uc720\uc728 15%\uc778 C\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 3\uc704 \uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\uc810\uc720\uc728\ubcf4\ub2e4 \ud070 \uacbd\uc6b0\uc758 B, C","\uc2dc\uc7a5\uc810\uc720\uc728 12%\uc5d0 \ubd88\uacfc\ud558\uace0 \uc2dc\uc7a5\uc810\uc720\uc728 \uc21c\uc704\uac00 3\uc704 \uc774\ud558\uc778 D","\uc2dc\uc7a5\uc810\uc720\uc728\uc774 \uac01\uac01 35%, 20%\uc778 3 \uc774\ud558\uc758 \uc0ac\uc5c5\uc790 \uc911 \ud558\ub098\uc778 E","\uacc4\uc5f4\ud68c\uc0ac \ud569\uc0b0 \uc810\uc720\uc728\uc774 40%\uc778 F"],t.s)
B.EO=s(["\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815"],t.s)
B.Jb=new A.c8("economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\ub85c \ucd94\uc815\ub418\uc9c0 \uc54a\ub294 \uacbd\uc6b0\ub294? (\uacc4\uc5f4\uad00\uacc4\ub294 \uc5c6\ub2e4\uace0 \uac00\uc815\ud558\uba70, \uc2dc\uc7a5\uc810\uc720\uc728\uc740 \uc5f0\uac04 \ub9e4\ucd9c\uc561 \uae30\uc900)",B.E8,2,"\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790 \ucd94\uc815\uc740 1\uac1c \uc0ac\uc5c5\uc790 \uc2dc\uc7a5\uc810\uc720\uc728 50% \uc774\uc0c1\uc774\uac70\ub098, 3\uac1c \uc774\ud558 \uc0ac\uc5c5\uc790\uc758 \ud569\uc0b0 \uc810\uc720\uc728\uc774 75% \uc774\uc0c1(\uc810\uc720\uc728 10% \ubbf8\ub9cc \uc0ac\uc5c5\uc790 \uc81c\uc678)\uc778 \uacbd\uc6b0 \ub4f1\uc5d0 \uc801\uc6a9\ub41c\ub2e4. \uc810\uc720\uc728\uc774 \ub0ae\uace0 \uc21c\uc704\uac00 \ub0ae\uc740 \uc0ac\uc5c5\uc790\ub294 \ucd94\uc815 \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4.",B.EO)
