B.J8=new A.c8("economic_law","\uc2dc\uc7a5\uc9c0\ubc30\uc801\uc9c0\uc704 \ub0a8\uc6a9","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc2dc\uc7a5\uc9c0\ubc30\uc801\uc0ac\uc5c5\uc790\uc758 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704 \uc720\ud615 \uc911 \uc0c8\ub85c\uc6b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704\uc5d0 \ud574\ub2f9\ud558\ub294 \uac83\uc744 \ubaa8\ub450 \uace0\ub978 \uac83\uc740?\n\n\u3131. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uac70\ub798\ud558\ub294 \uc720\ud1b5\uc0ac\uc5c5\uc790\uc640 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d\uc744 \uccb4\uacb0\ud558\ub294 \ud589\uc704\n\u3134. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \ub2e4\ub978 \uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ud65c\ub3d9\uc744 \ubc29\ud574\ud558\uae30 \uc704\ud574 \uc800\uac00\ub85c \uc0c1\ud488\uc744 \ud310\ub9e4\ud558\ub294 \ud589\uc704\n\u3137. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc0c8\ub85c\uc6b4 \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488 \uc0dd\uc0b0\uc5d0 \ud544\uc218\uc801\uc778 \uc694\uc18c\uc758 \uc0ac\uc6a9\uc744 \uac70\uc808\ud558\ub294 \ud589\uc704\n\u3139. \uc18c\ube44\uc790\uc758 \uc774\uc775\uc744 \ud604\uc800\ud788 \uc800\ud574\ud560 \uc6b0\ub824\uac00 \uc788\ub294 \uac00\uaca9\uc744 \uacb0\uc815\ud558\ub294 \ud589\uc704",B.E1,1,"\uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc758 \uc2dc\uc7a5\ucc38\uac00 \ubc29\ud574\ud589\uc704\uc5d0\ub294 \ubc30\ud0c0\uc801 \uac70\ub798\uacc4\uc57d \uccb4\uacb0, \ud544\uc218\uc694\uc18c\uc758 \uc0ac\uc6a9\xb7\uc811\uadfc \uac70\uc808 \ub4f1\uc774 \ud574\ub2f9\ud55c\ub2e4. \u3134\uc740 \uc0ac\uc5c5\ud65c\ub3d9\ubc29\ud574, \u3139\uc740 \uc18c\ube44\uc790\uc774\uc775 \uc800\ud574 \uc720\ud615\uc73c\ub85c \ubcc4\ub3c4\ub85c \ubd84\ub958\ub41c\ub2e4.",B.Dm)
B.Ev=s(["\uad6d\uc678\uc5d0\uc11c \uc774\ub8e8\uc5b4\uc9c4 \ud589\uc704\ub77c\ub3c4 \uadf8 \ud589\uc704\ub85c \uc778\ud55c \uc601\ud5a5\uc774 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \ubbf8\uce58\ub294 \uacbd\uc6b0 \uc774 \ubc95\uc774 \uc801\uc6a9\ub420 \uc218 \uc788\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \ud589\uc704\uac00 \uad6d\ub0b4\uc2dc\uc7a5\uc5d0 \uc601\ud5a5\uc744 \ubbf8\uce58\ub294\uc9c0 \uc5ec\ubd80\ub294 \uc9c1\uc811\uc801\uc774\uace0 \uc0c1\ub2f9\ud558\uba70 \ud569\ub9ac\uc801\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc601\ud5a5\uc744 \uae30\uc900\uc73c\ub85c \uc81c\ud55c \ud574\uc11d\ud55c\ub2e4","\uc678\uad6d\uc0ac\uc5c5\uc790\uc758 \uad6d\uc678\ud589\uc704\uac00 \uc678\uad6d \ubc95\ub960\uc0c1 \uc801\ubc95\ud558\ub2e4\uba74 \uadf8\ub7ec\ud55c \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc774 \ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub41c\ub2e4","\uc815\ubd80\ub294 \ub300\ud55c\ubbfc\uad6d\uc758 \ubc95\ub960 \ubc0f \uc774\uc775\uc5d0 \ubc18\ud558\uc9c0 \uc544\ub2c8\ud558\ub294 \ubc94\uc704\uc5d0\uc11c \uc678\uad6d\uc815\ubd80\uc640 \uc774 \ubc95 \uc9d1\ud589\uc744 \uc704\ud55c \ud611\uc815\uc744 \uccb4\uacb0\ud560 \uc218 \uc788\ub2e4","\uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uadfc\uac70 \uc870\ubb38\uc740 \uc774 \ubc95 \uc81c\uc815 \ub2f9\uc2dc\ubd80\ud130 \uc874\uc7ac\ud55c \uac83\uc740 \uc544\ub2c8\ub2e4"],t.s)
B.El=s(["\uc5ed\uc678\uc801\uc6a9"],t.s)
B.J3=new A.c8("economic_law","\ubaa9\uc801\xb7\ucd1d\uce59","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc758 \uc5ed\uc678\uc801\uc6a9\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc9c0 \uc54a\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.Ev,2,"\uc678\uad6d \ubc95\ub960\uc0c1 \uc801\ubc95\ud55c \ud589\uc704\ub77c \ud558\ub354\ub77c\ub3c4 \uadf8 \uc0ac\uc815\ub9cc\uc73c\ub85c \ub2f9\uc5f0\ud788 \uc6b0\ub9ac\ub098\ub77c \ubc95\uc758 \uc801\uc6a9\uc774 \ubc30\uc81c\ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub77c\ub294 \uac83\uc774 \ud310\ub840\uc758 \uc785\uc7a5\uc774\ub2e4.",B.El)
B.DV=s(["\ubd80\ub2f9\ud558\uac8c \uacbd\uc7c1\uc744 \uc81c\ud55c\ud558\ub294 \uacf5\ub3d9\ud589\uc704\ub85c \uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc758 \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \ud604\uc7ac \ub610\ub294 \uc7a5\ub798\uc758 \uc0ac\uc5c5\uc790 \uc218\ub97c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc758 \uc0ac\uc5c5\ub0b4\uc6a9 \ub610\ub294 \ud65c\ub3d9\uc744 \ubd80\ub2f9\ud558\uac8c \uc81c\ud55c\ud558\ub294 \ud589\uc704","\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub97c \ud558\ub3c4\ub85d \ubc29\uc870\ud558\ub294 \ud589\uc704","\uad6c\uc131\uc0ac\uc5c5\uc790\uc5d0\uac8c \uc0c1\ud488 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"],t.s)
B.Eo=s(["\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uc720\ud615"],t.s)
B.J2=new A.c8("economic_law","\uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc0ac\uc5c5\uc790\ub2e8\uccb4\uc758 \uae08\uc9c0\ud589\uc704\ub85c \uaddc\uc815\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.DV,4,"\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\ub294 \uac1c\ubcc4 \uc0ac\uc5c5\uc790\uc758 \uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9 \uc720\ud615\uc774\uba70, \ubc95\uc5d0\uc11c \uc5f4\uac70\ud55c \uc0ac\uc5c5\uc790\ub2e8\uccb4 \uae08\uc9c0\ud589\uc704 \uc720\ud615\uc5d0\ub294 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294\ub2e4.",B.Eo)
B.Ej=s(["\uc0ac\uc5c5\uc790\uac00 \uc0c1\ud488\uc744 \uac70\ub798\ud558\uba70 \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uac70\ub798\uac00\uaca9\uc744 \uc815\ud558\uc5ec \uadf8 \uac00\uaca9\ub300\ub85c \ud310\ub9e4\ud558\ub3c4\ub85d \uac15\uc81c\ud558\ub294 \ud589\uc704\ub294 \uad6c\uc18d\ub825 \uc5ec\ubd80\uc640 \uc0c1\uad00\uc5c6\uc774 \ud56d\uc0c1 \uae08\uc9c0\ub41c\ub2e4","\uc800\uc791\uad8c\ubc95\uc0c1 \uc800\uc791\ubb3c\ub85c\uc11c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc0c1\ud488\uc758 \uacbd\uc6b0 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub420 \uc218 \uc788\ub2e4","\ucd5c\uc800\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub294 \uc815\ub2f9\ud55c \uc774\uc720\uac00 \uc788\uc5b4\ub3c4 \ud5c8\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uae08\uc9c0\ub294 \uc6a9\uc5ed\uc758 \uc81c\uacf5\uc5d0\ub294 \uc801\uc6a9\ub418\uc9c0 \uc54a\ub294\ub2e4","\uc0ac\uc5c5\uc790\uac00 \uac15\uc81c\ub825 \uc5c6\ub294 \ud76c\ub9dd\uac00\uaca9\uc744 \uc81c\uc2dc\ud558\ub294 \ud589\uc704\ub3c4 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\ub85c \uae08\uc9c0\ub41c\ub2e4"],t.s)
B.DI=s(["\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704 \uc608\uc678"],t.s)
B.J0=new A.c8("economic_law","\uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uc5d0 \uad00\ud55c \uc124\uba85\uc73c\ub85c \uc633\uc740 \uac83\uc740? (\ub2e4\ud23c\uc774 \uc788\uc73c\uba74 \ud310\ub840\uc5d0 \ub530\ub984)",B.Ej,1,"\uc804\uc790\ucd9c\ud310\ubb3c \ub4f1 \uc77c\uc815\ud55c \uc800\uc791\ubb3c\ub85c\uc11c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\uc2dc\ud558\ub294 \uc0c1\ud488\uc5d0 \ub300\ud574\uc11c\ub294 \uc608\uc678\uc801\uc73c\ub85c \uc7ac\ud310\ub9e4\uac00\uaca9\uc720\uc9c0\ud589\uc704\uac00 \ud5c8\uc6a9\ub41c\ub2e4.",B.DI)
B.CN=s(["\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uae08\uc744 \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc0c1\ub2f9\ud788 \uc720\ub9ac\ud55c \uc870\uac74\uc73c\ub85c \uc790\uc0b0\xb7\uc0c1\ud488\xb7\uc6a9\uc5ed\uc744 \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \ubd80\ub2f9\ud55c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc0ac\uc5c5\uae30\ud68c\ub97c \uc81c\uacf5\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\ud569\ub9ac\uc801 \uace0\ub824\ub098 \ube44\uad50 \uc5c6\uc774 \uc0c1\ub2f9\ud55c \uaddc\ubaa8\ub85c \uac70\ub798\ud558\uc5ec \ud2b9\uc218\uad00\uacc4\uc778\uc5d0\uac8c \uc774\uc775\uc744 \uadc0\uc18d\uc2dc\ud0a4\ub294 \ud589\uc704","\uc2dc\uc7a5\uac00\uaca9\ubcf4\ub2e4 \ub0ae\uc740 \uac00\uaca9\uc73c\ub85c \uc77c\ubc18 \uc18c\ube44\uc790\uc5d0\uac8c \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\uc744 \uc81c\uacf5\ud558\ub294 \ud589\uc704"],t.s)
B.DO=s(["\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\uc77c\uac10\ubab0\uc544\uc8fc\uae30"],t.s)
B.J9=new A.c8("economic_law","\ud2b9\uc218\uad00\uacc4\uc778 \ubd80\ub2f9\uc774\uc775\uc81c\uacf5","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \ubd80\ub2f9\ud55c \uc774\uc775\uc81c\uacf5\ud589\uc704(\uc0ac\uc775\ud3b8\ucde8)\uc5d0 \ud574\ub2f9\ud558\uc9c0 \uc54a\ub294 \uac83\uc740?",B.CN,4,"\uc77c\ubc18 \uc18c\ube44\uc790\ub97c \ub300\uc0c1\uc73c\ub85c \ud55c \ud1b5\uc0c1\uc801\uc778 \ud310\ub9e4\ucd09\uc9c4 \ud560\uc778\uc740 \ud2b9\uc218\uad00\uacc4\uc778\uc5d0 \ub300\ud55c \uc774\uc775\uc81c\uacf5\uacfc \ubb34\uad00\ud558\uba70, \uc0ac\uc775\ud3b8\ucde8 \uaddc\uc81c \ub300\uc0c1\uc774 \uc544\ub2c8\ub2e4.",B.DO)
